// Geometry
const _dist = (ax,ay,bx,by) => Math.sqrt((ax-bx)**2+(ay-by)**2);
const dist = (a,b) => _dist(a.x,a.y,b.x,b.y);
const RAD2DEG = 180/Math.PI;
function angleDeg(from,vertex,to) { const a1=Math.atan2(from.y-vertex.y,from.x-vertex.x),a2=Math.atan2(to.y-vertex.y,to.x-vertex.x); let d=Math.abs(a2-a1)*RAD2DEG; if(d>180) d=360-d; return d; }
function lineCircleIntersections(p1,p2,center,radius) { const dx=p2.x-p1.x,dy=p2.y-p1.y,fx=p1.x-center.x,fy=p1.y-center.y,a=dx*dx+dy*dy,b=2*(fx*dx+fy*dy),c2=fx*fx+fy*fy-radius*radius; let disc=b*b-4*a*c2; if(disc<0)return[]; disc=Math.sqrt(disc); const pts=[]; for(const t of [(-b-disc)/(2*a),(-b+disc)/(2*a)]) if(t>=-0.01&&t<=1.01) pts.push({x:p1.x+t*dx,y:p1.y+t*dy}); return pts; }
function circleCircleIntersections(c1,r1,c2,r2) { const d=dist(c1,c2); if(d>r1+r2+1||d<Math.abs(r1-r2)-1||d<0.1) return[]; const a=(r1*r1-r2*r2+d*d)/(2*d),h2=r1*r1-a*a; if(h2<0) return[]; const h=Math.sqrt(h2),px=c1.x+a*(c2.x-c1.x)/d,py=c1.y+a*(c2.y-c1.y)/d; return [{x:px+h*(c2.y-c1.y)/d,y:py-h*(c2.x-c1.x)/d},{x:px-h*(c2.y-c1.y)/d,y:py+h*(c2.x-c1.x)/d}]; }
function segSegIntersection(a1,a2,b1,b2) { const d1x=a2.x-a1.x,d1y=a2.y-a1.y,d2x=b2.x-b1.x,d2y=b2.y-b1.y,cross=d1x*d2y-d1y*d2x; if(Math.abs(cross)<0.001) return null; const t=((b1.x-a1.x)*d2y-(b1.y-a1.y)*d2x)/cross,u=((b1.x-a1.x)*d1y-(b1.y-a1.y)*d1x)/cross; if(t>=-0.01&&t<=1.01&&u>=-0.01&&u<=1.01) return {x:a1.x+t*d1x,y:a1.y+t*d1y}; return null; }
function ptSegDist(px,py,ax,ay,bx,by) { const dx=bx-ax,dy=by-ay,lsq=dx*dx+dy*dy; if(lsq<0.001) return _dist(px,py,ax,ay); const t=Math.max(0,Math.min(1,((px-ax)*dx+(py-ay)*dy)/lsq)); return _dist(px,py,ax+t*dx,ay+t*dy); }

