function getPropNum(f){if(!f)return null;if(f.propNum)return f.propNum;const m=f.id?.match(/euclid-I\.(\d+)/);return m?parseInt(m[1]):null;}
function getAllowedPropositions(cf,custom){if(custom)return ALL_FILES.filter(f=>custom.includes(f.id));if(!cf||cf.source==="custom"||cf.source==="textbook")return ALL_FILES.filter(f=>f.requiredSteps);const num=getPropNum(cf);if(num===null)return ALL_FILES.filter(f=>f.requiredSteps);if(num===1)return[];return PROOF_FILES.filter(f=>{const n=getPropNum(f);return n!==null&&n<num;});}

function useResizable(init,min,max,side="left"){const[width,setWidth]=useState(init);const drag=useRef(false),startX=useRef(0),startW=useRef(0);const onMouseDown=useCallback((e)=>{e.preventDefault();drag.current=true;startX.current=e.clientX;startW.current=width;const onMove=(ev)=>{if(!drag.current)return;const d=side==="left"?(startX.current-ev.clientX):(ev.clientX-startX.current);setWidth(Math.max(min,Math.min(max,startW.current+d)));};const onUp=()=>{drag.current=false;window.removeEventListener("mousemove",onMove);window.removeEventListener("mouseup",onUp);};window.addEventListener("mousemove",onMove);window.addEventListener("mouseup",onUp);},[width,min,max,side]);return{width,onMouseDown};}

